// TG-144: Fetch today's scheduled jobs from Supabase
const supabaseUrl = 'https://lwtmvzhwekgdxkaisfra.supabase.co/rest/v1';
const supabaseKey = 'sb_publishable_DeX21ldoDKl3NyJeFZzR1w_eWBUkx-v';
const supabaseHeaders = {
  'apikey': supabaseKey,
  'Authorization': `Bearer ${supabaseKey}`
};

// Calculate today's date in CT (UTC-5 CDT / UTC-6 CST)
const now = new Date();
// At 11:00 UTC, CT is either 5 AM (CDT) or 6 AM (CST)
const ctOffset = -5; // CDT (summer); use -6 for CST
const ctNow = new Date(now.getTime() + ctOffset * 60 * 60 * 1000);
const todayStr = ctNow.toISOString().split('T')[0];

let jobs = [];
try {
  jobs = await this.helpers.httpRequest({
    method: 'GET',
    url: `${supabaseUrl}/jobber_email_events?event_type=eq.job_scheduled&parsed_scheduled_date=eq.${todayStr}&select=id,client_name,client_address,job_description,parsed_scheduled_time,customer_name,customer_address,service_type`,
    headers: supabaseHeaders
  });
} catch (e) {
  jobs = [];
}

if (!Array.isArray(jobs) || jobs.length === 0) {
  return [{ json: { jobs: [], _skip: true, message: 'No jobs scheduled for today', todayStr } }];
}

return [{ json: { jobs, todayStr, jobCount: jobs.length } }];

// TG-144: Check for yard signs due for collection (placed 7+ days ago)
const supabaseUrl = 'https://lwtmvzhwekgdxkaisfra.supabase.co/rest/v1';
const supabaseKey = 'sb_publishable_DeX21ldoDKl3NyJeFZzR1w_eWBUkx-v';
const supabaseHeaders = {
  'apikey': supabaseKey,
  'Authorization': `Bearer ${supabaseKey}`,
  'Content-Type': 'application/json',
  'Prefer': 'return=minimal'
};

const data = $input.first().json;
const sevenDaysAgo = new Date(Date.now() - 7 * 24 * 60 * 60 * 1000).toISOString();
const fourteenDaysAgo = new Date(Date.now() - 14 * 24 * 60 * 60 * 1000).toISOString();

let signsToCollect = [];
let expiredSigns = [];

try {
  // Signs placed 7+ days ago, still active
  signsToCollect = await this.helpers.httpRequest({
    method: 'GET',
    url: `${supabaseUrl}/yard_sign_placements?status=eq.active&placed_at=lte.${sevenDaysAgo}&select=id,customer_name,location,placed_at`,
    headers: { 'apikey': supabaseKey, 'Authorization': 'Bearer ' + supabaseKey }
  });
} catch (e) {
  signsToCollect = [];
}

try {
  // Auto-expire signs older than 14 days
  expiredSigns = await this.helpers.httpRequest({
    method: 'GET',
    url: `${supabaseUrl}/yard_sign_placements?status=eq.active&placed_at=lte.${fourteenDaysAgo}&select=id`,
    headers: { 'apikey': supabaseKey, 'Authorization': 'Bearer ' + supabaseKey }
  });

  if (Array.isArray(expiredSigns) && expiredSigns.length > 0) {
    for (const sign of expiredSigns) {
      try {
        await this.helpers.httpRequest({
          method: 'PATCH',
          url: `${supabaseUrl}/yard_sign_placements?id=eq.${sign.id}`,
          headers: supabaseHeaders,
          body: { status: 'expired', collected_at: new Date().toISOString() }
        });
      } catch (e) { /* continue */ }
    }
  }
} catch (e) {
  expiredSigns = [];
}

return [{ json: { ...data, signsToCollect: signsToCollect || [], expiredCount: (expiredSigns || []).length } }];

// TG-144: Build crew field reminder messages with marketing checklist
const data = $input.first().json;
const todayStr = data.todayStr || new Date().toISOString().split('T')[0];
const jobs = data.jobs || [];
const signsToCollect = data.signsToCollect || [];

if (data._skip && signsToCollect.length === 0) {
  return [{ json: { message: `No jobs scheduled for today (${todayStr}). No signs to collect. Enjoy the day!`, jobCount: 0 } }];
}

const parts = [];

// Header
parts.push(`DAILY FIELD MARKETING BRIEF`);
parts.push(`Date: ${todayStr}`);
parts.push(`Jobs today: ${jobs.length}`);
parts.push('');

// Job checklists
if (jobs.length > 0) {
  for (let i = 0; i < jobs.length; i++) {
    const job = jobs[i];
    const name = job.client_name || job.customer_name || 'Unknown';
    const address = job.client_address || job.customer_address || 'Address TBD';
    const service = job.job_description || job.service_type || 'Service TBD';
    const time = job.parsed_scheduled_time || 'Time TBD';

    parts.push(`--- JOB ${i + 1} ---`);
    parts.push(`Customer: ${name}`);
    parts.push(`Address: ${address}`);
    parts.push(`Service: ${service}`);
    parts.push(`Time: ${time}`);
    parts.push('');
    parts.push('FIELD MARKETING CHECKLIST:');
    parts.push('[ ] Place yard sign in visible front area');
    parts.push('[ ] Leave 3 door hangers on neighboring doors');
    parts.push('[ ] Carry business cards in truck');
    parts.push('[ ] Take a quick before/after photo');
    parts.push('[ ] Ask customer about Google review');
    parts.push('');
  }
}

// Yard sign collection reminders
if (signsToCollect.length > 0) {
  parts.push('--- SIGNS TO COLLECT ---');
  for (const sign of signsToCollect) {
    const placedDate = new Date(sign.placed_at);
    const daysAgo = Math.floor((Date.now() - placedDate.getTime()) / (24 * 60 * 60 * 1000));
    parts.push(`COLLECT SIGN: ${sign.location || sign.customer_name || 'Unknown'} (placed ${daysAgo} days ago)`);
  }
  parts.push('');
}

if (data.expiredCount > 0) {
  parts.push(`(${data.expiredCount} sign(s) auto-expired after 14 days)`);
}

const fullMessage = parts.join('\n');
return [{ json: { message: fullMessage, jobCount: jobs.length, signCollectCount: signsToCollect.length } }];

// TG-144: Log reminder run to automation_runs
const supabaseUrl = 'https://lwtmvzhwekgdxkaisfra.supabase.co/rest/v1';
const supabaseKey = 'sb_publishable_DeX21ldoDKl3NyJeFZzR1w_eWBUkx-v';

const data = $input.first().json;

try {
  await this.helpers.httpRequest({
    method: 'POST',
    url: `${supabaseUrl}/automation_runs`,
    headers: {
      'apikey': supabaseKey,
      'Authorization': `Bearer ${supabaseKey}`,
      'Content-Type': 'application/json',
      'Prefer': 'return=minimal'
    },
    body: {
      workflow_name: 'TG-144',
      event_type: 'crew_field_reminder',
      status: 'success',
      details: { job_count: data.jobCount || 0, sign_collect_count: data.signCollectCount || 0 },
      created_at: new Date().toISOString()
    }
  });
} catch (e) { /* continue on fail */ }

return [{ json: { logged: true } }];
